+				if (file instanceof TFile) {
+					await this.app.workspace.getLeaf(false).openFile(file);
+				}
+			}
+			new Notice(`Daily recall: ${matches.length} memories → ${path}`, 6000);
+		} catch (e) {
+			new Notice(`Daily recall failed: ${(e as Error).message}`, 6000);
+		}
+	}
