+					`index ${(stats as Record<string, unknown>).engine ?? "?"} ` +
+					`(${(stats as Record<string, unknown>).mode ?? "?"})`,
+				8000,
+			);
+		} catch (e) {
+			new Notice(`Brain unreachable: ${(e as Error).message}`, 6000);
+		}
+	}
+}

