+		el.createEl("pre").setText(sample);
+		setTimeout(() => el.remove(), 12000);
+	}
+}
+
+function hashColor(s: string): string {
+	let h = 0;
+	for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) | 0;
+	const hue = Math.abs(h) % 360;
+	return `hsl(${hue}, 55%, 55%)`;
