+	private async runSearch(): Promise<void> {
+		const q = this.state.query.trim();
+		if (!q) {
+			this.state.results = [];
+			this.state.error = null;
+			this.render();
+			return;
+		}
+		const { query, category } = parseCategoryPrefix(q);
+		const gen = ++this.generation;
+		this.state.loading = true;
+		this.state.error = null;
