+				this.state.selected + 1,
+			);
+			this.render();
+		} else if (e.key === "ArrowUp") {
+			e.preventDefault();
+			this.state.selected = Math.max(0, this.state.selected - 1);
+			this.render();
+		} else if (e.key === "Enter") {
+			e.preventDefault();
+			const r = this.state.results[this.state.selected];
+			if (r) void this.activate(r);
+		} else if (e.key === "Escape") {
